mapper.select:
SELECT * FROM SYSTEM_ASSET_INVENTORY


        AND ASSET_TYPE = #{assetType}


        AND OWNER_DOMAIN = #{ownerDomain}


        AND HEALTH_STATUS = #{healthStatus}


        AND ACTIVE_YN = #{activeYn}


ORDER BY ASSET_TYPE ASC, ASSET_NAME ASC

mapper.insert:
INSERT INTO SYSTEM_ASSET_COMPOSITION (
    COMPOSITION_ID, PARENT_ASSET_ID, CHILD_ASSET_ID, RELATION_TYPE, MAPPING_NOTES, CREATED_AT
) VALUES (
    #{compositionId}, #{parentAssetId}, #{childAssetId}, #{relationType}, #{mappingNotes}, CURRENT_DATETIME
)

INSERT INTO SYSTEM_ASSET_SCAN_LOG (
    SCAN_ID, ASSET_ID, PREVIOUS_HASH, CURRENT_HASH, SCAN_RESULT, SCAN_DETAILS, CREATED_AT
) VALUES (
    #{scanId}, #{assetId}, #{previousHash}, #{currentHash}, #{scanResult}, #{scanDetails, typeHandler=egovframework.com.config.data.CubridClobStringTypeHandler}, CURRENT_DATETIME
)

INSERT INTO SYSTEM_ASSET_LIFECYCLE_PLAN (
    PLAN_ID, ASSET_ID, TARGET_STAGE, PLAN_STATUS, REQUESTER_ID, TARGET_DATE, REASON, CREATED_AT, UPDATED_AT
) VALUES (
    #{planId}, #{assetId}, #{targetStage}, #{planStatus}, #{requesterId}, #{targetDate}, #{reason}, CURRENT_DATETIME, CURRENT_DATETIME
)

mapper.select:
SELECT PLAN_ID AS planId, ASSET_ID AS assetId, TARGET_STAGE AS targetStage, PLAN_STATUS AS planStatus, REQUESTER_ID AS requesterId, APPROVER_ID AS approverId, TARGET_DATE AS targetDate, REASON AS reason, CREATED_AT AS createdAt, UPDATED_AT AS updatedAt FROM SYSTEM_ASSET_LIFECYCLE_PLAN
AND ASSET_ID = #{assetId} AND PLAN_STATUS = #{status} AND TARGET_STAGE = #{stage}
ORDER BY CREATED_AT DESC

mapper.insert:
INSERT INTO SYSTEM_ASSET_LIFECYCLE_EVIDENCE (
    EVIDENCE_ID, PLAN_ID, CHECKPOINT_KEY, EVIDENCE_TYPE, EVIDENCE_VALUE, VERIFIED_BY, CREATED_AT
) VALUES (
    #{evidenceId}, #{planId}, #{checkpointKey}, #{evidenceType}, #{evidenceValue}, #{verifiedBy}, CURRENT_DATETIME
)
